# app/models/saved_report.rb
class SavedReport < ApplicationRecord
  belongs_to :creator, class_name: "User"

  # Only admins can create reports, and queries are reviewed/approved
  # before they can be executed
  enum :status, { draft: 0, approved: 1, rejected: 2 }

  validates :name, presence: true
  validates :query_template, presence: true
  validate :query_safety_check

  # Allowlist of tables and operations
  ALLOWED_TABLES = %w[
    orders products users page_views sessions
    revenue_summaries daily_metrics
  ].freeze

  FORBIDDEN_PATTERNS = [
    /\b(DROP|DELETE|TRUNCATE|ALTER|CREATE|INSERT|UPDATE|GRANT|REVOKE)\b/i,
    /\b(INTO\s+OUTFILE|INTO\s+DUMPFILE|LOAD_FILE|LOAD\s+DATA)\b/i,
    /\b(EXEC|EXECUTE|xp_|sp_)\b/i,
    /;\s*\S/,  # multiple statements
    /\/\*/,    # block comments used for obfuscation
    /--/,      # line comments
  ].freeze

  def query_safety_check
    if query_template.blank?
      errors.add(:query_template, "can't be blank")
      return
    end

    FORBIDDEN_PATTERNS.each do |pattern|
      if query_template.match?(pattern)
        errors.add(:query_template, "contains forbidden SQL pattern: #{pattern.source}")
        return
      end
    end

    unless query_template.strip.match?(/\A\s*SELECT\b/i)
      errors.add(:query_template, "must be a SELECT query")
    end
  end
end

# app/services/report_executor.rb
class ReportExecutor
  MAX_ROWS = 10_000
  QUERY_TIMEOUT_SECONDS = 30

  class QueryError < StandardError; end
  class UnauthorizedQuery < StandardError; end

  def initialize(saved_report, params: {})
    @report = saved_report
    @params = params.to_h.symbolize_keys
  end

  def execute
    raise UnauthorizedQuery, "Report must be approved before execution" unless @report.approved?

    query = build_parameterized_query
    results = execute_with_timeout(query)
    format_results(results)
  end

  private

  def build_parameterized_query
    # Use named placeholders that get sanitized
    template = @report.query_template.dup

    # Replace :param_name placeholders with sanitized values
    @params.each do |key, value|
      placeholder = ":#{key}"
      next unless template.include?(placeholder)

      sanitized = ActiveRecord::Base.connection.quote(value)
      template = template.gsub(placeholder, sanitized)
    end

    # Wrap in a limited subquery to prevent runaway results
    "SELECT * FROM (#{template}) AS report_result LIMIT #{MAX_ROWS}"
  end

  def execute_with_timeout(query)
    results = nil

    ActiveRecord::Base.connection_pool.with_connection do |conn|
      # Set statement timeout (PostgreSQL)
      conn.execute("SET LOCAL statement_timeout = '#{QUERY_TIMEOUT_SECONDS}s'")

      # Use a read-only transaction
      conn.transaction do
        conn.execute("SET TRANSACTION READ ONLY")
        raw = conn.exec_query(query)
        results = { columns: raw.columns, rows: raw.rows }
        raise ActiveRecord::Rollback # Always rollback — this is read-only
      end
    end

    results
  rescue ActiveRecord::StatementInvalid => e
    Rails.logger.error("Report query failed: #{e.message}")
    raise QueryError, "Query execution failed: #{e.message.truncate(200)}"
  end

  def format_results(results)
    return { columns: [], rows: [], total_rows: 0 } if results.nil?

    {
      columns: results[:columns],
      rows: results[:rows],
      total_rows: results[:rows].size,
      truncated: results[:rows].size >= MAX_ROWS
    }
  end
end

# app/controllers/admin/reports_controller.rb
module Admin
  class ReportsController < Admin::BaseController
    before_action :require_admin!
    before_action :require_report_approval_permission!, only: [:approve, :reject]
    before_action :set_report, only: [:show, :execute, :approve, :reject, :destroy]

    def index
      @reports = SavedReport.order(created_at: :desc).page(params[:page])
    end

    def new
      @report = SavedReport.new
    end

    def create
      @report = SavedReport.new(report_params)
      @report.creator = current_user
      @report.status = :draft

      if @report.save
        AuditLog.record!(
          user: current_user,
          action: "report_created",
          details: { report_id: @report.id, name: @report.name }
        )
        redirect_to admin_report_path(@report),
                    notice: "Report saved as draft. It must be approved before execution."
      else
        render :new, status: :unprocessable_entity
      end
    end

    def show
      @last_execution = @report.report_executions.order(created_at: :desc).first
    end

    def execute
      unless @report.approved?
        redirect_to admin_report_path(@report),
                    alert: "Report must be approved before execution."
        return
      end

      executor = ReportExecutor.new(@report, params: query_params)
      @results = executor.execute

      AuditLog.record!(
        user: current_user,
        action: "report_executed",
        details: {
          report_id: @report.id,
          params: query_params.to_h,
          row_count: @results[:total_rows]
        }
      )

      ReportExecution.create!(
        saved_report: @report,
        executed_by: current_user,
        row_count: @results[:total_rows],
        parameters: query_params.to_h
      )

      respond_to do |format|
        format.html { render :show }
        format.csv { send_csv_report(@results) }
        format.json { render json: @results }
      end
    rescue ReportExecutor::QueryError => e
      redirect_to admin_report_path(@report), alert: e.message
    rescue ReportExecutor::UnauthorizedQuery => e
      redirect_to admin_report_path(@report), alert: e.message
    end

    def approve
      @report.update!(status: :approved)
      AuditLog.record!(
        user: current_user,
        action: "report_approved",
        details: { report_id: @report.id }
      )
      redirect_to admin_report_path(@report), notice: "Report approved for execution."
    end

    def reject
      @report.update!(status: :rejected)
      AuditLog.record!(
        user: current_user,
        action: "report_rejected",
        details: { report_id: @report.id }
      )
      redirect_to admin_report_path(@report), notice: "Report rejected."
    end

    def destroy
      @report.destroy
      redirect_to admin_reports_path, notice: "Report deleted."
    end

    private

    def set_report
      @report = SavedReport.find(params[:id])
    end

    def report_params
      params.require(:saved_report).permit(:name, :description, :query_template)
    end

    def query_params
      params.fetch(:query_params, {}).permit!
      # These get individually quoted/sanitized in ReportExecutor
    end

    def require_admin!
      unless current_user&.admin?
        redirect_to root_path, alert: "Unauthorized"
      end
    end

    def require_report_approval_permission!
      unless current_user&.can_approve_reports?
        redirect_to admin_reports_path, alert: "You don't have permission to approve reports."
      end
    end

    def send_csv_report(results)
      csv_data = CSV.generate do |csv|
        csv << results[:columns]
        results[:rows].each { |row| csv << row }
      end

      send_data csv_data,
                filename: "report_#{@report.id}_#{Time.current.strftime('%Y%m%d%H%M%S')}.csv",
                type: "text/csv"
    end
  end
end

